#!/usr/bin/env python3
"""Counter-Intelligence Objective — Detect and neutralize other operators.
Honeypot detection, competing implant discovery, operator attribution."""
import hashlib
import json
import os
import re
import socket
import struct
import subprocess
import time

class CounterIntelEngine:
    """Counter-intelligence detection and analysis engine."""

    # Known honeypot signatures
    HONEYPOT_SIGNATURES = {
        'ssh': [
            ('Cowrie', r'SSH-2\.0-OpenSSH.*cowrie|kippo'),
            ('HoneySSH', r'SSH-2\.0-.*honey'),
            ('Dionaea', r'SSH-2\.0-.*dionaea'),
        ],
        'http': [
            ('Conpot', r'Siemens.*SCADA|conpot'),
            ('Glastopf', r'glastopf'),
            ('HoneyDB', r'honeydb'),
            ('T-Pot', r't-pot|tpot'),
        ],
        'filesystem': [
            ('Cowrie', ['/opt/cowrie', '/etc/cowrie', 'cowrie.cfg']),
            ('Dionaea', ['/opt/dionaea', '/etc/dionaea']),
            ('Conpot', ['/opt/conpot', 'conpot.cfg']),
            ('OpenCanary', ['/opt/opencanary', 'opencanary.conf']),
            ('T-Pot', ['/opt/tpot', 'docker-compose.yml']),
        ],
        'process': [
            ('Cowrie', ['cowrie', 'kippo']),
            ('Dionaea', ['dionaea']),
            ('Conpot', ['conpot']),
            ('OpenCanary', ['opencanary']),
            ('Honeyd', ['honeyd']),
            ('Artillery', ['artillery']),
        ],
        'network': [
            ('Excessive listeners', 20),  # >20 listening ports = suspicious
            ('All ports open', 100),      # >100 = definitely honeypot
        ],
    }

    # Known implant signatures
    IMPLANT_SIGNATURES = {
        'cobalt_strike': {
            'process_names': ['beacon.exe', 'artifact.exe'],
            'pipes': ['\\MSSE-', '\\msagent_', '\\postex_'],
            'default_ports': [50050, 443],
            'malleable_c2_markers': ['watermark', 'sleeptime', 'jitter'],
        },
        'metasploit': {
            'process_names': ['meterpreter', 'payload.exe'],
            'default_ports': [4444, 4445, 5555],
            'stager_markers': [b'\xfc\xe8', b'\xfc\x48'],  # x86/x64 shellcode headers
        },
        'sliver': {
            'default_ports': [31337, 8443],
            'mtls_markers': ['sliver', 'implant'],
        },
        'covenant': {
            'default_ports': [80, 443, 7443],
            'markers': ['Grunt', 'covenant'],
        },
    }

    def __init__(self):
        self.findings = []
        self.risk_score = 0

    def _add_finding(self, category, severity, description, evidence=None):
        finding = {
            'category': category,
            'severity': severity,  # critical, high, medium, low
            'description': description,
            'evidence': evidence,
            'timestamp': time.time(),
        }
        self.findings.append(finding)
        severity_scores = {'critical': 40, 'high': 25, 'medium': 10, 'low': 5}
        self.risk_score += severity_scores.get(severity, 0)

    def detect_honeypot_filesystem(self):
        """Check filesystem for honeypot indicators."""
        for hp_name, paths in self.HONEYPOT_SIGNATURES['filesystem']:
            for path in paths:
                if os.path.exists(path):
                    self._add_finding(
                        'honeypot', 'critical',
                        f'Honeypot detected: {hp_name} — file exists: {path}',
                        {'honeypot': hp_name, 'path': path}
                    )

    def detect_honeypot_processes(self):
        """Check running processes for honeypot indicators."""
        try:
            result = subprocess.run(['ps', 'aux'], capture_output=True, text=True, timeout=5)
            processes = result.stdout.lower()

            for hp_name, proc_names in self.HONEYPOT_SIGNATURES['process']:
                for pname in proc_names:
                    if pname.lower() in processes:
                        self._add_finding(
                            'honeypot', 'critical',
                            f'Honeypot process detected: {hp_name} ({pname})',
                            {'honeypot': hp_name, 'process': pname}
                        )
        except Exception:
            pass

    def detect_honeypot_network(self, target='127.0.0.1'):
        """Scan for honeypot network signatures."""
        open_ports = 0
        suspicious_ports = []

        for port in [21, 22, 23, 25, 80, 110, 143, 443, 445, 502, 1433, 1883, 3306, 3389, 5432, 5900, 8080, 8443, 10110]:
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                s.settimeout(1)
                result = s.connect_ex((target, port))
                if result == 0:
                    open_ports += 1
                    # Grab banner
                    try:
                        s.sendall(b'\r\n')
                        banner = s.recv(1024).decode(errors='replace')
                        # Check SSH honeypot
                        for hp_name, pattern in self.HONEYPOT_SIGNATURES['ssh']:
                            if re.search(pattern, banner, re.IGNORECASE):
                                self._add_finding(
                                    'honeypot', 'critical',
                                    f'SSH honeypot detected: {hp_name}',
                                    {'port': port, 'banner': banner[:200]}
                                )
                        # Check HTTP honeypot
                        for hp_name, pattern in self.HONEYPOT_SIGNATURES['http']:
                            if re.search(pattern, banner, re.IGNORECASE):
                                self._add_finding(
                                    'honeypot', 'high',
                                    f'HTTP honeypot detected: {hp_name}',
                                    {'port': port, 'banner': banner[:200]}
                                )
                    except Exception:
                        pass
                s.close()
            except Exception:
                pass

        if open_ports > 15:
            self._add_finding(
                'honeypot', 'high',
                f'Suspicious number of open ports: {open_ports} (honeypot indicator)',
                {'open_ports': open_ports}
            )

    def detect_competing_implants(self):
        """Detect other operators' implants on the system."""
        try:
            # Check running processes
            result = subprocess.run(['ps', 'aux'], capture_output=True, text=True, timeout=5)
            proc_list = result.stdout

            for framework, sigs in self.IMPLANT_SIGNATURES.items():
                for pname in sigs.get('process_names', []):
                    if pname.lower() in proc_list.lower():
                        self._add_finding(
                            'competing_implant', 'high',
                            f'Competing implant detected: {framework} — process: {pname}',
                            {'framework': framework, 'indicator': 'process'}
                        )

            # Check listening ports
            try:
                netstat = subprocess.run(['ss', '-tlnp'], capture_output=True, text=True, timeout=5)
                for framework, sigs in self.IMPLANT_SIGNATURES.items():
                    for port in sigs.get('default_ports', []):
                        if f':{port}' in netstat.stdout:
                            self._add_finding(
                                'competing_implant', 'medium',
                                f'Suspicious port for {framework}: {port}',
                                {'framework': framework, 'port': port}
                            )
            except Exception:
                pass

            # Check for suspicious scheduled tasks / cron
            try:
                crontab = subprocess.run(['crontab', '-l'], capture_output=True, text=True, timeout=5)
                if crontab.stdout:
                    suspicious = [line for line in crontab.stdout.split('\n') 
                                 if any(s in line.lower() for s in ['curl', 'wget', 'python', 'base64', '/tmp/', '/dev/shm/'])]
                    for line in suspicious:
                        self._add_finding(
                            'competing_implant', 'medium',
                            f'Suspicious cron entry: {line.strip()[:100]}',
                            {'indicator': 'cron', 'entry': line.strip()}
                        )
            except Exception:
                pass

            # Check /tmp and /dev/shm for implants
            for check_dir in ['/tmp', '/dev/shm', '/var/tmp']:
                if os.path.exists(check_dir):
                    for f in os.listdir(check_dir):
                        fpath = os.path.join(check_dir, f)
                        if os.path.isfile(fpath):
                            try:
                                size = os.path.getsize(fpath)
                                # Suspicious: executable in temp, recently modified
                                if os.access(fpath, os.X_OK) and size > 1024:
                                    mtime = os.path.getmtime(fpath)
                                    if time.time() - mtime < 86400:  # Last 24h
                                        self._add_finding(
                                            'competing_implant', 'medium',
                                            f'Suspicious executable in {check_dir}: {f} ({size}B)',
                                            {'path': fpath, 'size': size}
                                        )
                            except Exception:
                                pass
        except Exception:
            pass

    def detect_monitoring(self):
        """Detect if we're being monitored (EDR, SIEM agents, etc)."""
        monitoring_tools = {
            'sysmon': ['Sysmon', 'sysmon64'],
            'osquery': ['osqueryd', 'osqueryctl'],
            'auditd': ['auditd', 'ausearch'],
            'falco': ['falco'],
            'wazuh': ['wazuh-agent', 'ossec'],
            'crowdstrike': ['falcon-sensor', 'CSFalconService'],
            'sentinel_one': ['SentinelOne', 'sentinelctl'],
            'carbon_black': ['cb-psc-sensor', 'cbdaemon'],
        }

        try:
            result = subprocess.run(['ps', 'aux'], capture_output=True, text=True, timeout=5)
            for tool, procs in monitoring_tools.items():
                for proc in procs:
                    if proc.lower() in result.stdout.lower():
                        self._add_finding(
                            'monitoring', 'high',
                            f'Security monitoring detected: {tool} ({proc})',
                            {'tool': tool, 'process': proc}
                        )
        except Exception:
            pass

    def run_full_assessment(self, target='127.0.0.1'):
        """Run complete counter-intelligence assessment."""
        self.detect_honeypot_filesystem()
        self.detect_honeypot_processes()
        self.detect_honeypot_network(target)
        self.detect_competing_implants()
        self.detect_monitoring()

        # Determine overall assessment
        honeypot_findings = [f for f in self.findings if f['category'] == 'honeypot']
        implant_findings = [f for f in self.findings if f['category'] == 'competing_implant']
        monitoring_findings = [f for f in self.findings if f['category'] == 'monitoring']

        if any(f['severity'] == 'critical' for f in honeypot_findings):
            assessment = 'ABORT — Honeypot environment detected'
        elif self.risk_score > 80:
            assessment = 'HIGH RISK — Multiple indicators of monitoring/competition'
        elif self.risk_score > 40:
            assessment = 'ELEVATED — Some indicators present, proceed with caution'
        else:
            assessment = 'CLEAR — No significant counter-intelligence indicators'

        return {
            'assessment': assessment,
            'risk_score': self.risk_score,
            'findings_count': len(self.findings),
            'honeypot_indicators': len(honeypot_findings),
            'competing_implants': len(implant_findings),
            'monitoring_detected': len(monitoring_findings),
            'findings': self.findings,
        }


def main():
    import argparse
    parser = argparse.ArgumentParser(description='Counter-Intelligence Assessment')
    parser.add_argument('--target', default='127.0.0.1', help='Target for network checks')
    parser.add_argument('--json', action='store_true', help='JSON output')
    args = parser.parse_args()

    ci = CounterIntelEngine()
    result = ci.run_full_assessment(args.target)

    if args.json:
        print(json.dumps(result, indent=2))
    else:
        print(f'\n=== Counter-Intelligence Assessment ===')
        print(f'Assessment: {result["assessment"]}')
        print(f'Risk Score: {result["risk_score"]}')
        print(f'Findings: {result["findings_count"]}')
        for f in result['findings']:
            print(f'  [{f["severity"].upper()}] {f["description"]}')

if __name__ == '__main__':
    main()

